#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> asteroidCollision(vector<int>& asteroids) {
        vector<int> stack;
        for (int asteroid : asteroids) {
            bool added = false;
            while (!stack.empty() && stack.back() > 0 && asteroid < 0) {
                if (stack.back() < -asteroid) {
                    stack.pop_back();
                    continue;
                } else if (stack.back() == -asteroid) {
                    stack.pop_back();
                    added = true;
                    break;
                }
                added = true;
                break;
            }
            if (!added) {
                stack.push_back(asteroid);
            }
        }
        return stack;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> asteroids(n);
    for (int i = 0; i < n; i++) cin >> asteroids[i];
    Solution sol;
    vector<int> ans = sol.asteroidCollision(asteroids);
    cout << ans.size() << "\n";
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
